// Extract incoming message from webhook payload
// Supports WhatsApp Cloud API format or direct JSON { phone, message }
const body = $input.first().json.body || $input.first().json;

let senderPhone = '';
let messageText = '';
let senderName = '';

// WhatsApp Cloud API format
if (body.entry) {
  const entry = body.entry[0];
  const changes = entry.changes[0];
  const value = changes.value;

  if (!value.messages || !value.messages[0]) {
    return []; // Skip status updates
  }

  const msg = value.messages[0];
  senderPhone = msg.from;
  messageText = msg.text?.body || msg.interactive?.button_reply?.title || msg.interactive?.list_reply?.title || '';

  if (value.contacts && value.contacts[0]) {
    senderName = value.contacts[0].profile?.name || '';
  }
}
// Direct JSON format: { phone: '60123456789', message: 'hi', name: 'John' }
else if (body.phone || body.from) {
  senderPhone = body.phone || body.from;
  messageText = body.message || body.text?.body || body.body || '';
  senderName = body.name || body.profile_name || '';
}

// Normalize phone (remove + prefix)
senderPhone = senderPhone.replace(/^\+/, '');

if (!senderPhone || !messageText) {
  return [];
}

return {
  json: {
    senderPhone,
    messageText: messageText.trim(),
    senderName: senderName || 'Customer',
    timestamp: new Date().toISOString()
  }
};

// Parse customer lookup result and prepare context for AI Agent
const lookupResult = $input.first().json;

// The RPC returns an array; take first row or default to guest
const customer = Array.isArray(lookupResult) && lookupResult.length > 0
  ? lookupResult[0]
  : { customer_type: 'normal', pricing_label: 'Retail', is_registered: false, customer_name: 'Guest' };

const message = $('Extract Message').first().json.messageText;
const phone = $('Environment Setup').first().json.senderPhone;
const name = $('Environment Setup').first().json.senderName;

return {
  json: {
    customerType: customer.customer_type || 'normal',
    pricingLabel: customer.pricing_label || 'Retail',
    isRegistered: customer.is_registered || false,
    customerName: customer.customer_name || name || 'Customer',
    isMerchant: customer.customer_type === 'merchant',
    senderPhone: phone,
    messageText: message
  }
};

